+
+function emitOpenAiResponsesTextDeltaAndEnd(params: {
+  emit: TextEndBlockReplyHarness["emit"];
+  text: string;
+  delta?: string;
+  id: string;
+  phase?: OpenAiResponsesTextEventPhase;
